32	  AUTO_SESSION_END_INJECT_SOURCE,
33	} from "../control/auto-session-end-inject.js";
34	import { createChildLogger } from "../shared/logger.js";
35	import {
36	  INITIAL_WORK_QUESTION,
37	  INITIAL_WORK_INJECT_SOURCE,
38	  buildInitialWorkInjectText,
39	  buildInitialWorkOptions,
40	  formatDevelopmentTitle,
