65	const PatchSchema = z.object({
66	  current_task: z.string().optional(),
67	  branch: z.string().optional(),
68	  repo_path: z.string().min(1).optional(),
69	  repo_origin: z.string().nullable().optional(),
70	  /**
71	   * Shallow merge into session.metadata. Use `null` value to delete a key.
72	   * Lictor uses this post-spawn to publish `lictor_port` once the sidecar
73	   * is bound (the initial register happens BEFORE the port is known).
74	   */
75	  metadata: z.record(z.unknown()).optional(),
76	});
