84	const InjectSchema = z.object({
85	  text: z.string().min(1).max(4000),
86	  source: z.string().min(1).max(120).optional(),
87	  // 人間入力者の表示名 (ingress が付与)。参加者レジストリ登録 + ミラー発言者明示に使う。
