91	const TranscriptFrameSchema = z.object({
92	  seq: z.number().int().nonnegative(),
93	  kind: z.string().min(1).max(64),
94	  payload: z.unknown(),
95	});
96	
97	const PermissionRequestSchema = z.object({
98	  request_id: z.string().min(1).max(128),
99	  tool_name: z.string().min(1).max(128),
100	  tool_input: z.unknown(),
101	});
102	
103	const PermissionResponseSchema = z.object({
104	  request_id: z.string().min(1).max(128),
105	  decision: z.enum(["allow", "deny", "ask"]),
106	  reason: z.string().max(2000).optional(),
