109	/**
110	 * Body for POST /v1/sessions/:id/title-suggestion.
111	 * 上限 200 char は OSC タイトルの実用幅 + 多バイト混在を考慮して広めに取る.
112	 * 実際の rename は Lictor 側の sanitizer (32 char cap) が決める.
113	 */
114	const TitleSuggestionSchema = z.object({
115	  text: z.string().min(1).max(200),
116	});
117	// /:id/title 用 (window-title hook / rename コマンドから。Lictor へは転送しない)。
118	const TitleSetSchema = z.object({
119	  text: z.string().min(1).max(200),
120	});
121	// AskUserQuestion option は旧形式 string と新形式 {label, description?} の
122	// 両方を受け入れる. 内部 (DB / Discord embed) では正規化された {label, description?} で扱う.
123	const PendingQuestionOptionSchema = z.union([
124	  z.string().min(1).max(80),
125	  z.object({
126	    label: z.string().min(1).max(80),
127	    description: z.string().min(1).max(200).optional(),
128	  }),
129	]);
130	const PendingQuestionSchema = z.object({
131	  question: z.string().min(1).max(2000),
132	  options: z.array(PendingQuestionOptionSchema).min(1).max(25),
133	  multi_select: z.boolean().optional(),
134	});
135	// 回答は 3 形態のいずれか: 単一 (answer_index) / 複数 (answer_indices) / 自由文 (other_text)。
136	const AnswerQuestionSchema = z
137	  .object({
138	    question_id: z.number().int().positive(),
139	    answer_index: z.number().int().min(0).max(24).optional(),
140	    answer_indices: z.array(z.number().int().min(0).max(24)).min(1).max(25).optional(),
141	    other_text: z.string().min(1).max(2000).optional(),
142	  })
143	  .refine(
144	    (d) => d.answer_index !== undefined || d.answer_indices !== undefined || d.other_text !== undefined,
145	    { message: "one of answer_index / answer_indices / other_text required" },
146	  );
147	
148	const ForkSchema = z.object({
149	  /** Claude per-message uuid to resume from. Comes from the transcript frame's payload.claude_uuid. */
150	  claude_uuid: z.string().min(1).max(128),
151	  /** Working directory for the new session. Defaults to parent's repo_path. */
152	  cwd: z.string().min(1).optional(),
153	  /** Window vs tab — passed through to wt.exe spawner. */
154	  mode: z.enum(["tab", "window"]).optional(),
