177	function serializePersonaForResponse(p: PersonaRow) {
178	  let traits: unknown = [];
179	  let learned: unknown = [];
180	  try { traits = JSON.parse(p.traits); } catch { traits = []; }
181	  try { learned = JSON.parse(p.learned_notes); } catch { learned = []; }
182	  return {
183	    id: p.id,
184	    name: p.name,
185	    display_name: p.display_name ?? "",
186	    description: p.description,
187	    traits,
188	    speech_style: p.speech_style,
189	    skill_template: p.skill_template,
190	    learned_notes: learned,
191	  };
192	}
