194	export function sessionsRouter(deps: SessionsApiDeps): Hono {
195	  const app = new Hono();
196	
197	  // POST /v1/sessions  — start hook
198	  app.post("/", async (c) => {
199	    const body = await c.req.json().catch(() => null);
200	    const parsed = StartSchema.safeParse(body);
201	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
202	    const input = parsed.data;
203	    const now = nowSec();
204	
205	    const existing = deps.repo.findSession(input.id);
206	    if (existing) {
207	      // 既存セッションが lost / ended なら "再開" として active 化.
208	      // repo_path / repo_origin / branch は cwd 移動や checkout で変わり得るので毎回上書きする.
209	      if (existing.status !== "active") {
210	        deps.repo.setStatus(input.id, "active", now);
211	      } else {
212	        deps.repo.updateHeartbeat(input.id, now);
213	      }
214	      deps.repo.patchSession(input.id, {
215	        repo_path: input.repo_path,
216	        repo_origin: input.repo_origin ?? null,
217	        branch: input.branch ?? undefined,
218	      });
219	    } else {
220	      // delegation spawn 由来なら、 spawn 時に記録した (cwd, emoji) を repo_path で
221	      // claim してテンプレ絵文字を metadata へ焼く (Slack ライブカードの先頭アイコン)。
222	      const claimed = claimPendingDelegationSpawn(input.repo_path);
223	      const meta: Record<string, unknown> = { ...(input.metadata ?? {}) };
224	      if (claimed?.emoji) meta.delegation_emoji = claimed.emoji;
225	      if (claimed?.callName) meta.delegation_call_name = claimed.callName;
226	      deps.repo.insertSession({
227	        id: input.id,
228	        provider: input.provider as ProviderName,
229	        repo_path: input.repo_path,
230	        repo_origin: input.repo_origin ?? null,
231	        branch: input.branch ?? null,
232	        host: input.host,
233	        started_at: now,
234	        last_seen_at: now,
235	        transcript_path: input.transcript_path ?? null,
236	        metadata: Object.keys(meta).length ? JSON.stringify(meta) : null,
237	      });
238	      deps.repo.appendEvent({
239	        session_id: input.id,
240	        ts: now,
241	        kind: "start",
242	        payload: { provider: input.provider, host: input.host, cwd: input.repo_path, branch: input.branch ?? null },
243	      });
244	      eventBus.emit({
245	        type: "session.started",
246	        session_id: input.id,
247	        provider: input.provider,
248	        repo_path: input.repo_path,
249	        branch: input.branch ?? null,
250	        ts: now,
251	      });
252	    }
253	
254	    const session = deps.repo.findSession(input.id)!;
255	    const peers = deps.repo.findActivePeers(input.repo_path, input.id);
256	    const lostCandidates = deps.repo.findLostCandidates(input.repo_path, input.host);
257	    const advisory = buildAdvisory(session, peers);
258	
259	    // dev-process.md 由来のプロセスを auto-start (既に running なら skip).
260	    // FS / spawn を伴うので失敗は飲み込んで session 登録は完了させる.
261	    let processStartup: ReturnType<ProcessManager["startFromRepo"]> | null = null;
262	    try {
263	      processStartup = deps.processManager.startFromRepo(input.repo_path, input.repo_origin ?? null);
264	    } catch (err) {
265	      processStartup = {
266	        started: [],
267	        skipped: [],
268	        failed: [{ name: "*", reason: (err as Error).message }],
269	        warnings: [`startFromRepo error: ${(err as Error).message}`],
270	        marker_only: false,
271	        devProcessMdPath: null,
272	      };
273	    }
274	
275	    // persona を排他 assign (Concordia 経由で起動された session のみ. ここを叩いた時点で確定).
276	    const assignment = deps.personas.assign(input.id);
277	    if (assignment && !assignment.reused) {
278	      // 新規 assign なら role_label を session metadata に反映 (UI / dispatcher 共有用).
279	      const meta = parseMeta(session.metadata);
280	      meta.role_label = assignment.persona.name;
281	      meta.persona_id = assignment.persona.id;
282	      deps.repo.setMetadata(input.id, JSON.stringify(meta));
283	      eventBus.emit({
284	        type: "persona.assigned",
285	        session_id: input.id,
286	        persona_id: assignment.persona.id,
287	        persona_name: assignment.persona.name,
288	        ts: nowSec(),
289	      });
290	    }
291	
292	    const freshSession = deps.repo.findSession(input.id)!;
293	    const initialWorkOptions = await buildInitialWorkOptions(
294	      deps.repo,
295	      freshSession,
296	      deps.resolveWorkspaceRoots?.() ?? [input.repo_path],
297	    );
298	    const initialWorkQuestion = markInitialWorkQuestionAsked(deps.pendingQuestions, freshSession, initialWorkOptions);
299	    if (!initialWorkQuestion.deduped) {
300	      const ts = nowSec();
301	      deps.repo.appendEvent({
302	        session_id: input.id,
303	        ts,
304	        kind: "pending_question",
305	        payload: {
306	          question_id: initialWorkQuestion.questionId,
307	          question: INITIAL_WORK_QUESTION,
308	          options: initialWorkOptions,
309	          initial_work: true,
310	        },
311	      });
312	      setTimeout(() => {
313	        eventBus.emit({
314	          type: "question.posted",
315	          target_session_id: input.id,
316	          question_id: initialWorkQuestion.questionId,
317	          question: INITIAL_WORK_QUESTION,
318	          options: initialWorkOptions,
319	          ts,
320	        });
321	      }, 500).unref?.();
322	    }
323	
324	    return c.json({
325	      session: serializeSession(deps.repo.findSession(input.id)!),
326	      peers: peers.map(serializeSession),
327	      lost_candidates: lostCandidates.map(serializeSession),
328	      advisory,
329	      persona: assignment ? serializePersonaForResponse(assignment.persona) : null,
330	      persona_reused: assignment ? assignment.reused : false,
331	      processes: processStartup,
332	      process_stream_url: `ws://127.0.0.1:${deps.config.port}/ws`,
333	      initial_work: {
334	        question_id: initialWorkQuestion.questionId,
335	        question: INITIAL_WORK_QUESTION,
336	        options: initialWorkOptions,
337	      },
338	    });
339	  });
340	
341	  // GET /v1/sessions
342	  app.get("/", (c) => {
343	    const q = c.req.query();
344	    const list = deps.repo.listSessions({
345	      repo_origin: q.repo_origin || undefined,
346	      host: q.host || undefined,
347	      status: (q.status as SessionStatus) || undefined,
348	      provider: (q.provider as ProviderName) || undefined,
349	    });
350	    return c.json({ sessions: list.map(serializeSession) });
351	  });
352	
353	  // GET /v1/sessions/:id
354	  app.get("/:id", (c) => {
355	    const s = deps.repo.findSession(c.req.param("id"));
356	    if (!s) return c.json({ error: "not_found" }, 404);
357	    const events = deps.repo.recentEvents(s.id, 200);
358	    // persona (active assignment があれば) を同梱. statusline / UI が 1 リクエストで
359	    // ロール名 + 人物名を取れるように.
360	    const assignment = deps.personas.findActiveBySession(s.id);
361	    const persona = assignment ? deps.personas.find(assignment.persona_id) : null;
362	    return c.json({
363	      session: serializeSession(s),
364	      persona: persona ? serializePersonaForResponse(persona) : null,
365	      events: events.map((e) => ({
366	        id: e.id,
367	        ts: e.ts,
368	        kind: e.kind,
369	        payload: safeParse(e.payload),
370	      })),
371	    });
372	  });
373	
374	  // PATCH /v1/sessions/:id
375	  app.patch("/:id", async (c) => {
376	    const id = c.req.param("id");
377	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
378	    const body = await c.req.json().catch(() => null);
379	    const parsed = PatchSchema.safeParse(body);
380	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
381	    // Split off `metadata` — patchSession() only handles the column fields.
382	    const { metadata, ...columnPatch } = parsed.data;
383	    deps.repo.patchSession(id, columnPatch);
384	    if (metadata) deps.repo.mergeMetadata(id, metadata);
385	    deps.repo.updateHeartbeat(id, nowSec());
386	    if (parsed.data.current_task !== undefined) {
387	      deps.repo.appendEvent({
388	        session_id: id,
389	        ts: nowSec(),
390	        kind: "task_update",
391	        payload: { current_task: parsed.data.current_task },
392	      });
393	    }
394	    return c.json({ ok: true });
395	  });
396	
397	  // POST /v1/sessions/:id/heartbeat
398	  app.post("/:id/heartbeat", (c) => {
399	    const id = c.req.param("id");
400	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
401	    deps.repo.updateHeartbeat(id, nowSec());
402	    return c.json({ ok: true });
403	  });
404	
405	  // GET /v1/sessions/:id/tasks  — このセッションの TodoWrite 記録一覧.
406	  // task_update event がくるたびに upsert された session_task_records を返す.
407	  // - remaining: status !== "completed" の行 (= 残作業)
408	  // - completed: completed_at セット済みの行 (= 処理済み + 担当者)
409	  app.get("/:id/tasks", (c) => {
410	    const id = c.req.param("id");
411	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
412	    const items = deps.sessionTaskRecords.listBySession(id);
413	    const remaining = items.filter((t) => t.status !== "completed");
414	    const completed = items.filter((t) => t.completed_at !== null);
415	    const counts = deps.sessionTaskRecords.countBySessionStatus(id);
416	    return c.json({ items, remaining, completed, counts });
417	  });
418	
419	  // GET /v1/sessions/:id/pending-tasks  — hook が pull
420	  app.get("/:id/pending-tasks", (c) => {
421	    const id = c.req.param("id");
422	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
423	    const list = deps.tasks.pull(id, 20);
424	    return c.json({
425	      tasks: list.map((t) => ({
426	        id: t.id,
427	        kind: t.kind,
428	        payload: safeParse(t.payload),
429	        created_at: t.created_at,
430	        delivered_at: t.delivered_at,
431	      })),
432	    });
433	  });
434	
435	  // POST /v1/sessions/:id/event
436	  app.post("/:id/event", async (c) => {
437	    const id = c.req.param("id");
438	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
439	    const body = await c.req.json().catch(() => null);
440	    const parsed = EventSchema.safeParse(body);
441	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
442	    const ts = parsed.data.ts ?? nowSec();
443	    deps.repo.appendEvent({
444	      session_id: id,
445	      ts,
446	      kind: parsed.data.kind,
447	      payload: parsed.data.payload ?? {},
448	    });
449	    deps.repo.updateHeartbeat(id, ts);
450	    // prompt event は「いま何してるか」の最有力 signal なので current_task に反映
451	    if (parsed.data.kind === "prompt") {
452	      const summary = (parsed.data.payload as { summary?: unknown } | undefined)?.summary;
453	      if (typeof summary === "string" && summary.trim().length > 0) {
454	        deps.repo.patchSession(id, { current_task: summary.trim().slice(0, 200) });
455	      }
456	    }
457	    // task_update event は TodoWrite の状態遷移. session_task_records へ
458	    // upsert して残作業 / 完了 / 担当者 を per-task で記録.
459	    if (parsed.data.kind === "task_update") {
460	      const todos = (parsed.data.payload as { todos?: unknown } | undefined)?.todos;
461	      if (Array.isArray(todos)) {
462	        deps.sessionTaskRecords.applyTaskUpdate({
463	          session_id: id,
464	          todos: todos as Array<{ content?: unknown; activeForm?: unknown; status?: unknown }>,
465	          nowSec: ts,
466	        });
467	      }
468	    }
469	    const session = deps.repo.findSession(id)!;
470	    const eventCount = deps.repo.countEvents(id);
471	    deps.dispatcher.onEventAppended(session, eventCount);
472	    eventBus.emit({ type: "session.event", session_id: id, kind: parsed.data.kind, ts });
473	    return c.json({ ok: true });
474	  });
475	
476	  // POST /v1/sessions/:id/permission-request — Lictor's PreToolUse hook
477	  // is blocked waiting for a user decision. Emit a session-targeted event
478	  // so the Web UI modal shows up. We do NOT persist or block here — the
479	  // pending state lives in Lictor's sidecar (it has the resolver).
480	  app.post("/:id/permission-request", async (c) => {
481	    const id = c.req.param("id");
482	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
483	    const body = await c.req.json().catch(() => null);
484	    const parsed = PermissionRequestSchema.safeParse(body);
485	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
486	    eventBus.emit({
487	      type: "session.permission_request",
488	      target_session_id: id,
489	      request_id: parsed.data.request_id,
490	      tool_name: parsed.data.tool_name,
491	      tool_input: parsed.data.tool_input,
492	      ts: nowSec(),
493	    });
494	    return c.json({ ok: true });
495	  });
496	
497	  // POST /v1/sessions/:id/permission-response — Web UI's modal answer.
498	  // Proxied to Lictor's sidecar /v1/internal/permission-response, which
499	  // resolves the pending PreToolUse hook. Returns Lictor's status verbatim
500	  // so the Web UI can surface "session not running" / "already resolved" /
501	  // etc. when the response arrives too late.
502	  app.post("/:id/permission-response", async (c) => {
503	    const id = c.req.param("id");
504	    const body = await c.req.json().catch(() => null);
505	    const parsed = PermissionResponseSchema.safeParse(body);
506	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
507	    const target = resolveLictorTarget(deps.repo, id);
508	    if ("error" in target) return c.json({ error: target.error }, 404);
509	    let upstream: Response;
510	    try {
511	      upstream = await fetchFromLictor(target.port, "/v1/internal/permission-response", {
512	        method: "POST",
513	        headers: { "content-type": "application/json" },
514	        body: JSON.stringify(parsed.data),
515	      });
516	    } catch (err) {
517	      return c.json({ error: `lictor unreachable: ${(err as Error).message}` }, 502);
518	    }
519	    const text = await upstream.text();
520	    let json: unknown;
521	    try { json = JSON.parse(text); } catch { json = { raw: text }; }
522	    return c.json(json as Record<string, unknown>, upstream.status as 200);
523	  });
524	
525	  // POST /v1/sessions/:id/title — セッションのタイトル(やる事)を設定し title_renamed を
526	  // emit するだけ。Lictor /v1/rename には転送しない(= claude TUI に /rename を打ち込まない)
527	  // ので、window-title hook から毎回叩いても自セッションに slash 注入しない。
528	  // Discord は title_renamed で channel rename + status card 更新、Slack は thread root 反映。
529	  app.post("/:id/title", async (c) => {
530	    const id = c.req.param("id");
531	    if (!deps.repo.findSession(id)) return c.json({ error: "not_found" }, 404);
532	    const body = await c.req.json().catch(() => null);
533	    const parsed = TitleSetSchema.safeParse(body);
534	    if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
535	    const now = nowSec();
536	    // current_task も更新する。 Discord は title_renamed の payload からタイトルを読むが、
537	    // Slack ライブカードは session.current_task を読むため、 ここを書かないと rename が
538	    // Slack カードに反映されない (📌 がセッション id 先頭8桁のまま固まる)。
