975	  app.post("/:id/resume", async (c) => {
976	    const oldId = c.req.param("id");
977	    const old = deps.repo.findSession(oldId);
978	    if (!old) return c.json({ error: "not_found" }, 404);
979	    const body = await c.req.json().catch(() => ({}));
980	    const newId = body?.new_session_id;
