141	                SUM(CASE WHEN status = 'active'    THEN 1 ELSE 0 END) AS active,
142	                SUM(CASE WHEN status = 'lost'      THEN 1 ELSE 0 END) AS lost,
143	                SUM(CASE WHEN status = 'ended'     THEN 1 ELSE 0 END) AS ended,
144	                SUM(CASE WHEN status = 'abandoned' THEN 1 ELSE 0 END) AS abandoned,
145	                MAX(last_seen_at) AS last_seen_at
146	           FROM sessions
147	          GROUP BY host
148	          ORDER BY MAX(last_seen_at) DESC`,
149	      )
150	      .all() as Array<{
151	        host: string;
152	        active: number;
153	        lost: number;
154	        ended: number;
155	        abandoned: number;
156	        last_seen_at: number;
157	      }>;
158	  }
159	
160	  /**
161	   * Shallow-merge `partial` into the session's existing metadata blob.
162	   * Keys present in `partial` overwrite; missing keys are preserved.
163	   * `null` value for a key DELETES that key. No-op when session is missing.
164	   *
165	   * Used by Lictor to publish its sidecar port after the pty/sidecar start
166	   * (the initial register happens BEFORE the sidecar is bound, so port is
167	   * not known yet).
168	   */
169	  mergeMetadata(id: string, partial: Record<string, unknown>): void {
170	    const row = this.findSession(id);
171	    if (!row) return;
172	    let current: Record<string, unknown> = {};
173	    if (row.metadata) {
174	      try {
175	        const parsed = JSON.parse(row.metadata) as unknown;
176	        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
177	          current = parsed as Record<string, unknown>;
178	        }
179	      } catch {
180	        // existing metadata is garbage — treat as empty rather than crash.
181	      }
182	    }
183	    for (const [k, v] of Object.entries(partial)) {
184	      if (v === null) delete current[k];
185	      else current[k] = v;
186	    }
187	    this.setMetadata(id, JSON.stringify(current));
188	  }
189	
190	  countEvents(sessionId: string): number {
191	    const r = this.db
192	      .prepare(`SELECT COUNT(*) AS n FROM session_events WHERE session_id = ?`)
193	      .get(sessionId) as { n: number };
194	    return r.n;
195	  }
196	
197	  /** started_at が [startTs, endTs) の session 集合. day_report 集計用. */
198	  listSessionsInRange(startTs: number, endTs: number): SessionRow[] {
199	    return this.db
200	      .prepare(
201	        `SELECT * FROM sessions WHERE started_at >= ? AND started_at < ? ORDER BY started_at ASC`,
202	      )
203	      .all(startTs, endTs) as SessionRow[];
204	  }
205	
206	  setStatus(id: string, status: SessionStatus, ts: number, endedAt?: number): void {
207	    this.db
208	      .prepare(
209	        `UPDATE sessions SET status = ?, last_seen_at = ?, ended_at = COALESCE(?, ended_at) WHERE id = ?`,
210	      )
