216	   * active かつ last_seen_at が古い session のうち **WS 永続クライアントが繋がっていない** ものだけ返す.
217	   * ws_clients > 0 の session は「作業中」 と見なして lost 化対象から除外する
218	   * (考え事 / build / 入力待ちで hook が静止しても誤 lost を防ぐ).
219	   */
220	  findStaleActive(cutoff: number): SessionRow[] {
221	    return this.db
222	      .prepare(
223	        `SELECT * FROM sessions
224	         WHERE status = 'active' AND last_seen_at < ? AND ws_clients = 0`,
225	      )
226	      .all(cutoff) as SessionRow[];
227	  }
228	
229	  // ─── WS persistent client (active 判定の主軸) ─────────
