         WHERE id = ?`,
      )
      .run(now, sessionId);
    if (Number(r.changes ?? 0) === 0) return 0;
    const row = this.db
      .prepare(`SELECT ws_clients FROM sessions WHERE id = ?`)
      .get(sessionId) as { ws_clients: number } | undefined;
    return row?.ws_clients ?? 0;
  }

