    .prepare(`SELECT paused FROM sessions WHERE id = ?`)
    .get(id) as { paused: number } | undefined;
  return row ? Boolean(row.paused) : false;
}

setPaused(id: string, paused: boolean): void {
  this.db
    .prepare(`UPDATE sessions SET paused = ? WHERE id = ?`)
    .run(paused ? 1 : 0, id);
