    .prepare(`UPDATE sessions SET paused = ? WHERE id = ?`)
    .run(paused ? 1 : 0, id);
}

togglePaused(id: string): boolean {
  const current = this.getPaused(id);
  this.setPaused(id, !current);
  return !current;
}

