      session_id: peer.id,
      kind: "session-departed",
      payload: {
        lost_session_id: lost.id,
        lost_role: role,
        lost_branch: lost.branch,
        lost_repo: lost.repo_path,
        last_task: lastTask,
        instructions:
          "離脱通知. 残作業に介入が必要そうなら chitchat に一言流すか、 ユーザに伝える程度で十分.",
      },
    });
  }
}

