24	/** 深夜帯抑制を受けないよう昼帯に固定 (14:00 local). */
25	const DAYTIME = () => new Date(2026, 4, 22, 14, 0, 0);
26	/** 深夜帯 (23:00–翌05:00) テスト用 (02:00 local). */
27	const NIGHT = () => new Date(2026, 4, 22, 2, 0, 0);
28	
29	describe("Dispatcher (smarter triggers)", () => {
30	  let env: ReturnType<typeof fresh>;
31	  beforeEach(() => { env = fresh(); });
32	
33	  it("review-summary fires when work-event count is multiple of 5", () => {
34	    startSession(env.sessions, "a");
35	    const d = new Dispatcher({ ...env, rng: () => 0.99, now: DAYTIME });
36	    for (let i = 0; i < 5; i++) {
37	      env.sessions.appendEvent({
38	        session_id: "a", ts: i, kind: "edit",
39	        payload: { file: "src/foo.ts" },
40	      });
41	    }
