describe("Dispatcher paused sessions — 一時停止セッションを提案・通知対象から外す", () => {
  let env: ReturnType<typeof fresh>;
  beforeEach(() => { env = fresh(); });

  it("paused セッションの onEventAppended は何も enqueue しない", () => {
    startSession(env.sessions, "paused-session");
    env.sessions.setPaused("paused-session", true);
    env.sessions.appendEvent({
      session_id: "paused-session", ts: 1, kind: "prompt", payload: { summary: "hi" },
    });
    const d = new Dispatcher({ ...env, rng: () => 0.01, now: DAYTIME });
    const session = env.sessions.findSession("paused-session")!;
    d.onEventAppended(session, 1);
    const pulled = env.tasks.pull("paused-session");
    expect(pulled.find((t) => t.kind === "chitchat-suggest")).toBeFalsy();
  });

  it("paused セッションは onChatPosted の chat-reply 対象から除外される", () => {
    startSession(env.sessions, "a");
    startSession(env.sessions, "b-paused");
    startSession(env.sessions, "c");
    env.sessions.setPaused("b-paused", true);
    const d = new Dispatcher({ ...env, rng: () => 0.05, now: DAYTIME });
    d.onChatPosted({
      id: 1, channel: "chitchat", session_id: "a",
      text: "雑談", author_label: "テスト魂", is_actionable: false,
    });
    expect(env.tasks.pull("b-paused").find((t) => t.kind === "chat-reply")).toBeFalsy();
    expect(env.tasks.pull("c").find((t) => t.kind === "chat-reply")).toBeTruthy();
  });

  it("paused セッションは onSessionLost の session-departed 通知対象から除外される", () => {
    startSession(env.sessions, "lost");
    startSession(env.sessions, "active");
    startSession(env.sessions, "paused");
    env.sessions.setStatus("lost", "lost", 100);
    env.sessions.setPaused("paused", true);
    const d = new Dispatcher({ ...env, rng: () => 0.99 });
    d.onSessionLost(env.sessions.findSession("lost")!);
    expect(env.tasks.pull("active").find((t) => t.kind === "session-departed")).toBeTruthy();
    expect(env.tasks.pull("paused").find((t) => t.kind === "session-departed")).toBeFalsy();
  });

  it("paused セッションは onLogUpdate の peer-log-react 対象から除外される", () => {
    startSession(env.sessions, "src");
    startSession(env.sessions, "p1");
    startSession(env.sessions, "p2-paused");
    env.sessions.setPaused("p2-paused", true);
    const d = new Dispatcher({ ...env, rng: () => 0.5 });
    d.onLogUpdate({ kind: "rule.add", ref: "r1", source_session_id: "src", summary: "added" });
    expect(env.tasks.pull("p2-paused").find((t) => t.kind === "peer-log-react")).toBeFalsy();
    // p1 が反応対상
    const reactions = env.tasks.pull("p1").filter((t) => t.kind === "peer-log-react");
    expect(reactions.length).toBeGreaterThan(0);
  });
});

